// 1. Lấy giá trị thô từ Yolo:bit
let rawValue = parseFloat(msg.payload);
if (isNaN(rawValue)) return null; // Bỏ qua nếu dữ liệu rác

// 2. Phân tích Topic nội bộ (VD: z_1/r_1/soil)
let internalTopic = msg.topic;
let topicParts = internalTopic.split('/');
let metricName = topicParts[topicParts.length - 1]; // Lấy chữ 'soil' hoặc 'temp'

// 3. Xác định đơn vị (Unit) theo chuẩn SenML
let unit = "";
if (metricName === "temp") unit = "Cel";
else if (metricName === "humidity" || metricName === "soil") unit = "%RH";
else if (metricName === "pump") unit = "boolean";

// 4. Đóng gói thành SenML JSON
let senml = {
    "bn": "user_admin/gh_alpha/" + internalTopic + "/",
    "e": [
        {
            "n": metricName,
            "u": unit,
            "v": rawValue,
            "t": Math.floor(Date.now() / 1000) // Timestamp hiện tại
        }
    ]
};

// 5. Chuẩn bị bản tin để gửi lên Cloud
msg.payload = senml;
// Nối thêm tiền tố để ra Shared Topic
msg.topic = "user_admin/gh_alpha/" + internalTopic;

return msg;
